SELECT COUNT(gene_set_id) AS active_gene_set_count
FROM gene_sets
WHERE is_active = 1;

SELECT COUNT(*) AS active_gene_set_count
FROM gene_sets
WHERE is_active = 1;

SELECT gene_set_id
FROM gene_sets
WHERE false_discovery_rate < 0.01;

SELECT COUNT(*) AS total_active_clusters 
FROM clusters 
WHERE is_active = 1;

SELECT AVG(nominal_p_value) AS average_nominal_p_value
FROM gene_sets
WHERE species = 'Homo sapiens';

SELECT gene_set_id 
FROM gene_sets 
ORDER BY gene_set_id;

SELECT COUNT(DISTINCT gene_set_id) AS total_gene_sets
FROM gene_sets
WHERE nominal_p_value < 0.05 AND species = 'Human';
